mapper.select:
SELECT A.reviewSeq, A.productSeq, A.userId, A.userName, A.score, A.contents, A.imageUrl, DATE_FORMAT(A.createdAt,'%Y-%m-%d'), B.productName FROM review A INNER JOIN product B ON A.productSeq = B.productSeq WHERE A.productSeq = #{productSeq}
ORDER BY A.createdAt DESC
ORDER BY A.score DESC, A.createdAt DESC
LIMIT 10 OFFSET #{offset}

mapper.delete:
DELETE
FROM review
WHERE userId = #{userId}
AND reviewSeq = #{reviewSeq}

mapper.select:
SELECT  COUNT(*)
FROM review A
WHERE A.productSeq = #{productSeq}
